export function getPunjabiArticleBySlug(slug: string): Wave1Article | undefined {
  return punjabiBlogArticles.find((a) => a.slug === slug);
}

export function getPublishedPunjabiArticles(): Wave1Article[] {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  return punjabiBlogArticles.filter(article => {
    const publishDate = new Date(article.publishDate || article.datePublished);
    publishDate.setHours(0, 0, 0, 0);
    return publishDate <= today;
  });
}
